mapper.select:
SELECT pi.id AS paperId, pi.paper_title AS paperTitle, pi.paper_type AS paperType, -- paper_info 中论文状态映射到 submitStatus：auditing=2待审核、completed=3已完成、others=1待处理 CASE pi.paper_status WHEN 'auditing' THEN 2 WHEN 'completed' THEN 3 WHEN 'rejected' THEN 4 ELSE 1 END AS submitStatus, CASE pi.paper_status WHEN 'auditing' THEN '待审核' WHEN 'completed' THEN '导师指导完成' WHEN 'rejected' THEN '已驳回' ELSE '待处理' END AS submitStatusDesc, pi.student_id AS id, su.real_name AS userName, pi.major_id AS majorId, pi.teacher_id AS advisorId, pi.submit_time AS submitTime, pi.allocation_time AS advisorAssignTime, tu.real_name AS advisorName FROM paper_submit ps -- 关联论文表（获取论文状态等） INNER JOIN paper_info pi ON ps.paper_id = pi.id AND pi.is_deleted = 0 -- 关联学生表 LEFT JOIN sys_user su ON pi.student_id = su.id AND su.is_deleted = 0 -- 关联导师表 LEFT JOIN sys_user tu ON pi.teacher_id = tu.id AND tu.is_deleted = 0 WHERE pi.teacher_id = #{advisorId} AND ps.is_deleted = 0
AND ( CASE pi.paper_status WHEN 'auditing' THEN 2 WHEN 'completed' THEN 3 WHEN 'rejected' THEN 4 ELSE 1 END ) = #{status}
-- 取每篇论文最新一次提交记录 AND ps.submit_version = ( SELECT MAX(ps2.submit_version) FROM paper_submit ps2 WHERE ps2.paper_id = ps.paper_id AND ps2.is_deleted = 0 ) ORDER BY pi.allocation_time DESC
